mapper.select:
SELECT n.id, n.user_id AS userId, n.type, n.content,
       n.is_read AS isRead, n.created_at AS createdAt,
       n.sender_id AS senderId, n.target_id AS targetId,
       n.target_type AS targetType,
       u.username AS senderName, u.avatar_url AS senderAvatar
FROM notifications n
LEFT JOIN users u ON u.id = n.sender_id

    n.user_id = #{userId}
    AND n.type = #{type}
    AND n.is_read = #{isRead}

ORDER BY n.created_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM notifications

    user_id = #{userId}
    AND type = #{type}
    AND is_read = #{isRead}

SELECT n.id, n.user_id AS userId, n.type, n.content,
       n.is_read AS isRead, n.created_at AS createdAt,
       n.sender_id AS senderId, n.target_id AS targetId,
       n.target_type AS targetType,
       u.username AS senderName, u.avatar_url AS senderAvatar,
       recipient.username AS recipientName
FROM notifications n
LEFT JOIN users u ON u.id = n.sender_id
LEFT JOIN users recipient ON recipient.id = n.user_id

    AND n.type = #{type}
    AND n.user_id = #{userId}
    AND n.created_at >= #{startTime}
    AND n.created_at <= #{endTime}

ORDER BY n.created_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM notifications n

    AND n.type = #{type}
    AND n.user_id = #{userId}
    AND n.created_at >= #{startTime}
    AND n.created_at <= #{endTime}
